const body = request.body || {};
const keyString = body.clave || "";
const text = body.texto || "";

if (!keyString || !text) {
  $_EXCEPTION_("Los campos 'clave' y 'texto' son obligatorios", null, 400);
}

const key = crypto.createHash('sha256').update(String(keyString)).digest();
const iv = crypto.randomBytes(16);
const cipher = crypto.createCipheriv('aes-256-cbc', key, iv);
let encrypted = cipher.update(text, 'utf8', 'base64');
encrypted += cipher.final('base64');

const encryptedText = iv.toString('hex') + ':' + encrypted;

$_RETURN_DATA_ = { encrypted: encryptedText };
